{
  "name": "flashcard-app",
  "version": "0.1.0",
  "private": true,
  "description": "Minimal Express server base for flash card app",
  "scripts": {
    "start": "node server.js",
    "dev": "nodemon server.js",
    "test": "jest --runInBand"
  },
  "dependencies": {
    "express": "^4.19.2"
  },
  "devDependencies": {
    "jest": "^29.7.0",
    "supertest": "^6.3.4",
    "nodemon": "^3.1.0"
  },
  "jest": {
    "testEnvironment": "node"
  }
}

const app = require('./app');

const PORT = process.env.PORT || 7995;

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT}`);
});

const express = require('express');
const path = require('path');

const app = express();

// Parse JSON bodies
app.use(express.json());

// Serve static files from public/
const publicDir = path.join(__dirname, 'public');
app.use(express.static(publicDir));

// Health check endpoint
app.get('/health', (_req, res) => {
  res.status(200).json({ status: 'ok' });
});

module.exports = app;

'use strict';

function generateId() {
  // Simple unique-ish ID: [8 rand chars][time base36]
  return Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
}

function assertNonEmptyString(value, fieldName) {
  if (typeof value !== 'string') {
    const err = new Error(`${fieldName} must be a string`);
    err.code = 'VALIDATION_ERROR';
    throw err;
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    const err = new Error(`${fieldName} must be a non-empty string`);
    err.code = 'VALIDATION_ERROR';
    throw err;
  }
  return trimmed;
}

function assertValidId(id) {
  if (typeof id !== 'string' || id.trim().length === 0) {
    const err = new Error('id must be a non-empty string');
    err.code = 'VALIDATION_ERROR';
    throw err;
  }
  return id.trim();
}

function createFlashcard(front, back) {
  const cleanFront = assertNonEmptyString(front, 'front');
  const cleanBack = assertNonEmptyString(back, 'back');
  return { id: generateId(), front: cleanFront, back: cleanBack };
}

module.exports = {
  createFlashcard,
  assertNonEmptyString,
  assertValidId,
};

'use strict';

const fs = require('fs');
const fsp = fs.promises;
const path = require('path');
const { createFlashcard, assertNonEmptyString, assertValidId } = require('./flashcard');

const DATA_DIR = process.env.FLASHCARD_DATA_DIR || path.join(__dirname, '..', 'data');
const DATA_FILE = path.join(DATA_DIR, 'cards.json');

async function ensureDir() {
  await fsp.mkdir(DATA_DIR, { recursive: true });
}

async function readAll() {
  try {
    const data = await fsp.readFile(DATA_FILE, 'utf8');
    const parsed = JSON.parse(data);
    if (!Array.isArray(parsed)) {
      const err = new Error('Data file is invalid: expected an array');
      err.code = 'DATA_INVALID';
      throw err;
    }
    return parsed;
  } catch (err) {
    if (err && (err.code === 'ENOENT')) {
      // No file yet
      return [];
    }
    throw err;
  }
}

async function writeAll(cards) {
  await ensureDir();
  const tmpFile = path.join(DATA_DIR, `cards.json.tmp-${process.pid}-${Date.now()}`);
  const payload = JSON.stringify(cards, null, 2) + '\n';
  await fsp.writeFile(tmpFile, payload, { encoding: 'utf8' });
  await fsp.rename(tmpFile, DATA_FILE);
}

async function getAllCards() {
  const cards = await readAll();
  return cards;
}

async function addCard({ front, back }) {
  const card = createFlashcard(front, back);
  const cards = await readAll();
  cards.push(card);
  await writeAll(cards);
  return card;
}

async function updateCard(id, { front, back }) {
  const cleanId = assertValidId(id);
  const cleanFront = assertNonEmptyString(front, 'front');
  const cleanBack = assertNonEmptyString(back, 'back');
  const cards = await readAll();
  const index = cards.findIndex(c => c.id === cleanId);
  if (index === -1) {
    const err = new Error('Card not found');
    err.code = 'NOT_FOUND';
    throw err;
  }
  const updated = { ...cards[index], front: cleanFront, back: cleanBack };
  cards[index] = updated;
  await writeAll(cards);
  return updated;
}

async function deleteCard(id) {
  const cleanId = assertValidId(id);
  const cards = await readAll();
  const index = cards.findIndex(c => c.id === cleanId);
  if (index === -1) {
    const err = new Error('Card not found');
    err.code = 'NOT_FOUND';
    throw err;
  }
  const newCards = cards.slice(0, index).concat(cards.slice(index + 1));
  await writeAll(newCards);
  return true;
}

module.exports = {
  getAllCards,
  addCard,
  updateCard,
  deleteCard,
  // Expose paths for introspection if needed
  _paths: { DATA_DIR, DATA_FILE }
};

const request = require('supertest');
const app = require('../app');

describe('Express base server', () => {
  it('GET /health returns 200 with {status:"ok"}', async () => {
    const res = await request(app).get('/health');
    expect(res.status).toBe(200);
    expect(res.body).toEqual({ status: 'ok' });
  });

  it('serves public/index.html at /', async () => {
    const res = await request(app).get('/');
    expect(res.status).toBe(200);
    expect(res.text).toMatch(/Flashcard\s+App/i);
  });
});

const fs = require('fs');
const fsp = fs.promises;
const path = require('path');
const os = require('os');

async function loadStorageInTempDir() {
  const dir = await fsp.mkdtemp(path.join(os.tmpdir(), 'flashcards-test-'));
  process.env.FLASHCARD_DATA_DIR = dir;
  jest.resetModules();
  const storage = require('../lib/storage');
  return { storage, dir };
}

async function readDataFile(dir) {
  const file = path.join(dir, 'cards.json');
  try {
    const data = await fsp.readFile(file, 'utf8');
    return JSON.parse(data);
  } catch (e) {
    return null;
  }
}

async function cleanupDir(dir) {
  await fsp.rm(dir, { recursive: true, force: true });
}

describe('storage.js CRUD', () => {
  it('getAllCards returns [] when file does not exist', async () => {
    const { storage, dir } = await loadStorageInTempDir();
    try {
      const all = await storage.getAllCards();
      expect(Array.isArray(all)).toBe(true);
      expect(all.length).toBe(0);
    } finally {
      await cleanupDir(dir);
    }
  });

  it('addCard creates data dir/file on first write and returns created card with id', async () => {
    const { storage, dir } = await loadStorageInTempDir();
    try {
      const created = await storage.addCard({ front: ' Front text ', back: ' Back text ' });
      expect(created).toHaveProperty('id');
      expect(typeof created.id).toBe('string');
      expect(created.front).toBe('Front text');
      expect(created.back).toBe('Back text');

      const fileData = await readDataFile(dir);
      expect(Array.isArray(fileData)).toBe(true);
      expect(fileData.length).toBe(1);
      expect(fileData[0].id).toBe(created.id);
    } finally {
      await cleanupDir(dir);
    }
  });

  it('updateCard updates fields and persists changes', async () => {
    const { storage, dir } = await loadStorageInTempDir();
    try {
      const created = await storage.addCard({ front: 'A', back: 'B' });
      const updated = await storage.updateCard(created.id, { front: 'X', back: 'Y' });
      expect(updated.front).toBe('X');
      expect(updated.back).toBe('Y');

      const all = await storage.getAllCards();
      expect(all[0].front).toBe('X');
      expect(all[0].back).toBe('Y');
    } finally {
      await cleanupDir(dir);
    }
  });

  it('deleteCard removes the item and persists', async () => {
    const { storage, dir } = await loadStorageInTempDir();
    try {
      const a = await storage.addCard({ front: 'A', back: 'A1' });
      const b = await storage.addCard({ front: 'B', back: 'B1' });
      expect((await storage.getAllCards()).length).toBe(2);
      const ok = await storage.deleteCard(a.id);
      expect(ok).toBe(true);
      const all = await storage.getAllCards();
      expect(all.length).toBe(1);
      expect(all[0].id).toBe(b.id);
    } finally {
      await cleanupDir(dir);
    }
  });

  it('rejects invalid payloads with clear errors', async () => {
    const { storage, dir } = await loadStorageInTempDir();
    try {
      await expect(storage.addCard({ front: '', back: 'B' })).rejects.toThrow(/front/i);
      await expect(storage.addCard({ front: 'A', back: '' })).rejects.toThrow(/back/i);
      const created = await storage.addCard({ front: 'ok', back: 'ok' });
      await expect(storage.updateCard(created.id, { front: '', back: 'x' })).rejects.toThrow(/front/i);
      await expect(storage.updateCard(created.id, { front: 'x', back: '' })).rejects.toThrow(/back/i);
      await expect(storage.updateCard('nonexistent', { front: 'a', back: 'b' })).rejects.toThrow(/not found/i);
      await expect(storage.deleteCard('nonexistent')).rejects.toThrow(/not found/i);
    } finally {
      await cleanupDir(dir);
    }
  });
});
